import{_ as s,c as t,a as i,o as a}from"./app-CEcM0piI.js";const d={};function n(r,e){return a(),t("div",null,e[0]||(e[0]=[i(`<p>直接调用函数方法：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select 函数(参数);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>可以和sql语句配合使用</p><h1 id="字符串函数" tabindex="-1"><a class="header-anchor" href="#字符串函数"><span>字符串函数</span></a></h1><table><thead><tr><th>函数</th><th>功能</th></tr></thead><tbody><tr><td>CONCAT(S1,S2....Sn)</td><td>字符串拼接，将S1，S2，….Sn拼接成一个字符串</td></tr><tr><td>LOWER(str)</td><td>将字符串str全部转为小写</td></tr><tr><td>UPPER(str)</td><td>将字符串str全部转为大写</td></tr><tr><td>LPAD(str,n,pad)</td><td>左填充，用字符串pad对str的左边进行填充，达到n个字符串长度</td></tr><tr><td>RPAD(str,n,pad)</td><td>右填充，用字符串pad对str的右边进行填充，达到n个字符串长度</td></tr><tr><td>TRIM(str)</td><td>去掉字符串头部和尾部的空格</td></tr><tr><td>SUBSTRING(str,start,len)</td><td>返回从字符串str从start位置起的len个长度的字符串</td></tr></tbody></table><h1 id="数值函数" tabindex="-1"><a class="header-anchor" href="#数值函数"><span>数值函数</span></a></h1><table><thead><tr><th>函数</th><th>功能</th></tr></thead><tbody><tr><td>CEIL(x)<br></td><td>向上取整</td></tr><tr><td>FLOOR(x)<br></td><td>向下取整</td></tr><tr><td>MOD(x,y)<br></td><td>返回x/y的模</td></tr><tr><td>RAND()<br></td><td>返回0~1内的随机数</td></tr><tr><td>ROUND(x,y)</td><td>求参数x的四舍五入的值，保留y位小数</td></tr></tbody></table><h1 id="日期函数" tabindex="-1"><a class="header-anchor" href="#日期函数"><span>日期函数</span></a></h1><table><thead><tr><th>函数</th><th>功能</th></tr></thead><tbody><tr><td>CURDATE()</td><td>返回当前日期</td></tr><tr><td>CURTIME()</td><td>返回当前时间</td></tr><tr><td>NOW()</td><td>返回当前日期和时间获取指定date的年份</td></tr><tr><td>YEAR(date)</td><td>获取指定date的年份</td></tr><tr><td>MONTH(date)</td><td>获取指定date的月份</td></tr><tr><td>DAY(date)</td><td>获取指定date的日期</td></tr><tr><td>DATE_ADD(date, INTERVAL expr type)</td><td>返回一个日期/时间值加上一个时间间隔expr后的时间值</td></tr><tr><td>DATEDIFF(date1,date2)</td><td>返回起始时间date1和结束时间date2之间的天数</td></tr></tbody></table><h1 id="流程函数" tabindex="-1"><a class="header-anchor" href="#流程函数"><span>流程函数</span></a></h1><table><thead><tr><th>函数</th><th>功能</th></tr></thead><tbody><tr><td>lF(value ,t , f)</td><td>如果value为true，则返回t，否则返回f</td></tr><tr><td>IFNULL(value1 ,value2)</td><td>如果value1不为空，返回value1，否则返回value2</td></tr><tr><td>CASE WHEN [val1 ] THEN [res1]... ELSE [ default] END</td><td>如果val1为true，返回res1，..否则返回default默认值（when和then可以有很多个）</td></tr><tr><td>CASE [ expr ] WHEN [val1 ] THEN [res1] ... ELSE [ default] END</td><td>如果expr的值等于val1，返回res1，..否则返回default默认值（when和then可以有很多个）</td></tr></tbody></table><h1 id="约束" tabindex="-1"><a class="header-anchor" href="#约束"><span>约束</span></a></h1><p>作用于表中字段上的规则，用于限制存储在表中的数据 保证数据库中数据的正确性、有效性、完整性</p><table><thead><tr><th>约束</th><th>描述</th><th>关键字</th></tr></thead><tbody><tr><td>非空约束</td><td>制该字段的数据不能为null</td><td>NOT NULL</td></tr><tr><td>唯一约束</td><td>保证该字段的所有数据都是唯一、不重复的</td><td>UNIQUE</td></tr><tr><td>主键约束</td><td>主键是一行数据的唯一标识，要求非空且唯一</td><td>PRIMARY KEY</td></tr><tr><td>默认约束</td><td>保存数据时，如果未指定该字段的值，则采用默认值</td><td>DEFAULT</td></tr><tr><td>检查约束(8.0.16版本之后)</td><td>保证字段值满足某一个条件</td><td>CHECK</td></tr><tr><td>外键约束</td><td>用来让两张表的数据之间建立连接，保证数据的一致性和完整性</td><td>FOREIGN KEY<br></td></tr><tr><td>约束是作用在表中字段上的，可以在创建表/修改表的时候添加约束</td><td></td><td></td></tr><tr><td>一个字段可以添加多个约束</td><td></td><td></td></tr></tbody></table><p>示例：</p><table><thead><tr><th>字段名</th><th>字段含义</th><th>字段类型</th><th>约束条件</th><th>约束关键字</th></tr></thead><tbody><tr><td>id</td><td>ID唯一标识</td><td>int</td><td>主键，并且自动增长</td><td>PRIMARY KEY, AUTO_INCREMENT</td></tr><tr><td>name</td><td>姓名</td><td>varchar(10)</td><td>不为空，并且唯一</td><td>NOT NULL, UNIQUE</td></tr><tr><td>age</td><td>年龄</td><td>int</td><td>大于0，并且小于等于120</td><td>CHECK</td></tr><tr><td>status</td><td>状态</td><td>char(1)</td><td>如果没有指定该值，默认为1</td><td>DEFAULT</td></tr><tr><td>gender</td><td>性别</td><td>char(1)</td><td>无</td><td></td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>create table user(  </span></span>
<span class="line"><span>    id      int         primary key auto_increment  comment&#39;主键&#39;,  </span></span>
<span class="line"><span>    name    varchar(10) not null unique             comment&#39;姓名&#39;,  </span></span>
<span class="line"><span>    age     int         check(age&gt;0 &amp;&amp; age &lt;=120)   comment&#39;年龄&#39;,  </span></span>
<span class="line"><span>    status  char(1)     default&#39;1&#39;                  comment&#39;状态&#39;,  </span></span>
<span class="line"><span>    gender  char(1)                                 comment&#39;性别&#39;  </span></span>
<span class="line"><span>)comment&#39;用户表&#39;;</span></span>
<span class="line"><span>insert into user(name, age, status, gender) values(&#39;tom&#39;,19,1,&#39;男&#39;),(&#39;jerry&#39;,25,1,&#39;男&#39;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>不需要插入id数据，数据库也能自动添加</p><h2 id="外键约束" tabindex="-1"><a class="header-anchor" href="#外键约束"><span>外键约束</span></a></h2><p>让两张表的数据之间建立连接从而保证数据的一致性和完整性 ![[Clip_2024-03-07_21-18-32.png]]</p><blockquote><p>[!warning] 注意 目前上述的两张表，在数据库层面并未建立外键关联，所以是无法保证数据的一致性和完整性的。</p></blockquote><h4 id="添加外键" tabindex="-1"><a class="header-anchor" href="#添加外键"><span>添加外键：</span></a></h4><p>创建表的时候直接添加</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>CREATE TABLE表名(</span></span>
<span class="line"><span>	字段名 数报类型</span></span>
<span class="line"><span>	……</span></span>
<span class="line"><span>	[CONSTRAINT] [外键名称] FOREIGN KEY(外键字段名) REFERENCES 主表(主表列名)</span></span>
<span class="line"><span>);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>表结构创建好后再添加</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ALTER TABLE 表名 ADD CONSTRAINT 外键名称 FOREIGN KEY(外键字段名) REFERENCES 主表(主表列名);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>示例： 在创建表后添加外键</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>alter table emp add constraint fk_emp_dept_id foreign key (dept_id) references dept(id);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在删除外键连接的列时会判断与父表使用外键连接的子表中是否有与该列相关的键如果有就阻止删除</p><h4 id="删除外键" tabindex="-1"><a class="header-anchor" href="#删除外键"><span>删除外键</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ALTER TABLE 表名 DROP FOREIGN KEY 外键名称；</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="删除-更新行为" tabindex="-1"><a class="header-anchor" href="#删除-更新行为"><span>删除/更新行为</span></a></h4><table><thead><tr><th>行为</th><th>说明</th></tr></thead><tbody><tr><td>NO ACTION</td><td>当在父表中删除/更新对应记录时，首先检查该记录是否有对应外键，如果有则不允许删除/更新。（与RESTRICT一致）</td></tr><tr><td>RESTRICT</td><td>当在父表中删除/更新对应记录时，首先检查该记录是否有对应外键，如果有则不允许删除/更新。（与NOACTION一致）</td></tr><tr><td>CASCADE</td><td>当在父表中删除/更新对应记录时，首先检查该记录是否有对应外键，如果有，则也删除/更新外键在子表中的记录。</td></tr><tr><td>SET NULL</td><td>当在父表中删除/更新对应记录时，首先检查该记录是否有对应外键，如果有，则也删除/更新外键在子表中的记录。（设为null）</td></tr><tr><td>SET DEFAULT</td><td>父表有变更时，子表将外键列设置成一个默认的值（Innodb不支持）</td></tr><tr><td>语法：在添加外键的语法后面加上关键字</td><td></td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ALTER TABLE 表名 ADD CONSTRAINT 外键名称 FOREIGN KEY(外键字段) REFERENCES 主表名(主表字段名) ON UPDATE CASCADE ON DELETE CASCADE;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>on update 和on delete分别指在更新时和删除时做什么</p><h1 id="多表查询" tabindex="-1"><a class="header-anchor" href="#多表查询"><span>多表查询</span></a></h1><h1 id="笛卡尔积" tabindex="-1"><a class="header-anchor" href="#笛卡尔积"><span>笛卡尔积</span></a></h1><p>使用select可以查询多个表</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select * from emp,dept;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>但查询出来数据并不符合直觉，其中一个表中的主键都要和另一个表中的主键进行匹配，查询出来的数据量就是两个表中数据的乘积，这种现象就被称为笛卡尔积</p><p>笛卡尔乘积指在数学中两个集合A和集合B的所有组合情况 在多表查询时，需要消除无效的笛卡尔积 要消除无效的笛卡尔积就需要添加条件限制，根据两个表某一字段的对应关系进行筛选</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select * from emp,dept where emp.dept_id=dept.id;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="分类" tabindex="-1"><a class="header-anchor" href="#分类"><span>分类</span></a></h1><h2 id="连接查询" tabindex="-1"><a class="header-anchor" href="#连接查询"><span>连接查询</span></a></h2><h3 id="内连接" tabindex="-1"><a class="header-anchor" href="#内连接"><span>内连接</span></a></h3><p>相当于查询a、b交集部分数据</p><p><strong>隐式内连接</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select 字段列表 from 表名（可多选） where 条件;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>之前的例子就是隐式内连接，如果筛选的字段的某个是null则不属于两者交集部分就不会显示出来</p><p><strong>显式内连接</strong> 显式内连接和隐式内连接作用相同 但是显式连接可以减少字段的扫描，有更快的执行速度。这种速度优势在3张或更多表连接时比较明显</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select 字段列表 from 表1 [inner] join 表2 on 连接条件;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>示例：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select e.name,d.name from emp e inner join dept d on e.dept_id = d.id;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="外连接" tabindex="-1"><a class="header-anchor" href="#外连接"><span>外连接</span></a></h3><p><strong>左外连接</strong> 查询左表所有数据以及两张表交集部分数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select 字段列表 from 表1 left [outer] join 表2 on 条件;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>示例：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select e.*,d.name from emp e left outer join dept d on d.id = e.dept_id;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>右外连接</strong> 查询右表所有数据以及两帮表交集部分数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select 字段列表 from 表1 right [outer] join 表2 on 条件;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>自连接</strong> 当前表与自身的连接查询，自连接必须使用表别名 即将一张表的两个别名看作两张表来操作</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select 字段列表 from 表1 别名a join 表1 别名b on 条件;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如：一个表中员工有自己的id以及自己直属领导id（领导也在这个表中）就可以通过自连接查询员工的直属领导</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select a.name,b.name from emp a, emp b  where a.managerid=b.id;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>但是查询到的只是交集，如果某人没有直属领导（领导id为null）就不会显示出来 此时需要使用外连接查询出所有数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>select a.name,b.name from emp a left outer join emp b on a.managerid=b.id;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="union联合查询" tabindex="-1"><a class="header-anchor" href="#union联合查询"><span>union联合查询</span></a></h2><p>对于union查询，就是把多次查询的结果合并起来，形成一个新的查询结果集。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>SELECT 字段列表 FROM 表A...</span></span>
<span class="line"><span>UNION [ALL]</span></span>
<span class="line"><span>SELECT 字段列表 FROM 表B...；</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>all：是否去重，如果存在两个条件都满足的元素不使用all会去重只显示一次，使用all每次都会显示 省略号表示没有写完后面可以跟sql语句进行选择性查询 多张表的列数必须一致，字段类型也必须一致</p><h2 id="子查询" tabindex="-1"><a class="header-anchor" href="#子查询"><span>子查询</span></a></h2><p>SQL语句中嵌套SELECT语句，称为嵌套查询，又称子查询。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>SELECT *FROM t1 WHERE column1 =(SELECT column1 FROM t2 );</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>子查询外部的语句可以是INSERT/UPDATE/DELETE /SELECT的任何一个。 根据子查询结果不同，分为:</p><h3 id="标量子查询" tabindex="-1"><a class="header-anchor" href="#标量子查询"><span>标量子查询</span></a></h3><p>子查询结果为单个值：数字，字符串，日期等 常用操作符：= &lt;&gt; &gt; &gt;= &lt; &lt;=</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>查询“销售部”的所有员工信息</span></span>
<span class="line"><span>a.查询“销售部”部门ID</span></span>
<span class="line"><span>select id from dept where name =</span></span>
<span class="line"><span>&#39;销售部&#39;;</span></span>
<span class="line"><span>根据销售部门id查询员工信息</span></span>
<span class="line"><span>select * from emp where dept_id=4;</span></span>
<span class="line"><span>使用标量子查询</span></span>
<span class="line"><span>select * from emp where dent id = (select id from dent where name =&#39;销售部&#39;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="列子查询" tabindex="-1"><a class="header-anchor" href="#列子查询"><span>列子查询</span></a></h3><p>子查询返回的结果是一列（可以是多行），这种子查询称为列子查询。 常用操作符：</p><table><thead><tr><th>操作符</th><th>描述描述</th></tr></thead><tbody><tr><td>IN</td><td>在指定的集合范围之内，多选一</td></tr><tr><td>NOT IN</td><td>不在指定的集合范围之内</td></tr><tr><td>ANY</td><td>子查询返回列表中，有任意一个满足即可</td></tr><tr><td>SOME</td><td>与ANY等同，使用SOME的地方都可以使用ANY</td></tr><tr><td>ALL</td><td>子查询返回列表的所有值都必须满足</td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>查询比 财务部 所有工资都高的员工信息</span></span>
<span class="line"><span>a.查询所有 财务部 人员工资</span></span>
<span class="line"><span>select salary from emp where dept_id=(select id from emp where name=&#39;财务部&#39;);</span></span>
<span class="line"><span>b.比财务部 所有人工资都高的员工信</span></span>
<span class="line"><span>select * from emp where salary &gt; all (select salary from emp where dept_id =(select id from dept where name=&#39;财务部&#39;));</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="行子查询" tabindex="-1"><a class="header-anchor" href="#行子查询"><span>行子查询</span></a></h3><p>子查询返回的结果是一行（可以是多列），这种子查询称为行子查询。 常用的操作符：=、&lt;&gt;、IN、NOT IN</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>-- 1.查询与“张无忌”的薪资及直属领导相同的员工信息</span></span>
<span class="line"><span>--a.查询“张无忌”的薪资及直属领导</span></span>
<span class="line"><span>select salary, managerid from emp where name =&#39;张无忌”;</span></span>
<span class="line"><span>b.查询与“张无忌”的薪资及直属领导相同的员工信息；</span></span>
<span class="line"><span>select * from emp where (salary,managerid) = (select salary, managerid from emp where name =&#39;张无忌&#39;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="表子查询" tabindex="-1"><a class="header-anchor" href="#表子查询"><span>表子查询</span></a></h3><p>子查询返回的结果是多行多列，这种子查询称为表子查询。 常用的操作符：IN</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>1.查询与“鹿杖客”，“宋远桥”的职位和薪资相同的员工信息</span></span>
<span class="line"><span>a、查询“鹿杖客”，“宋远桥”的职位和薪资</span></span>
<span class="line"><span>select job, salary from emp where name =&#39;鹿杖客&#39;or name=‘宋远桥&#39;;</span></span>
<span class="line"><span>b、食询与“鹿杖客”，“宋远桥”的职位和薪资相同的员工信息</span></span>
<span class="line"><span>select * from emp where (job,salary) in ( select job, salary from emp where name =&#39;鹿杖客&#39;or name =&#39;宋远桥&#39;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>根据子查询位置，分为：WHERE之后、FROM之后、SELECT之后。</p><h1 id="事务" tabindex="-1"><a class="header-anchor" href="#事务"><span>事务</span></a></h1><h1 id="简介" tabindex="-1"><a class="header-anchor" href="#简介"><span>简介</span></a></h1><p>事务是一组操作的集合，它是一个不可分割的工作单位，事务会把所有的操作作为一个整体一起向系统提交或撤销操作请求，即这些操作要么同时成功，要么同时失败。 如：张三给李四转一千块钱操作分为以下步骤 查询张三账户余额 张三账户余额-1000 李四账户余额+1000 如果在给李四账户余额+1000操作时出了问题张三的钱减了但李四的钱没加显然是不行的 这种情况就要用到数据库的事务操作 MySQL的事务默认是自动提交的，也就是说每次执行sql语句都会隐式提交事务</p><h1 id="操作" tabindex="-1"><a class="header-anchor" href="#操作"><span>操作</span></a></h1><p>查看/设置事务提交方式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>SELECT @@autocommit;</span></span>
<span class="line"><span>SET @@autocommit=0;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果是1就是自动提交，0就是手动提交</p><p>提交事务</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>COMMIT;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>回滚事务</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ROLLBACK;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>开启事务</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>START TRANSACTION 或 BEGIN;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="事务的四大特性" tabindex="-1"><a class="header-anchor" href="#事务的四大特性"><span>事务的四大特性</span></a></h1><p>原子性（Atomicity）：事务是不可分割的最小操作单元，要么全部成功，要么全部失败。 一致性（Consistency）：事务完成时，必须使所有的数据都保持一致状态。 隔离性（Isolation）：数据库系统提供的隔离机制，保证事务在不受外部并发操作影响的独立环境下运行。 持久性（Durability）：事务一旦提交或回滚，它对数据库中的数据的改变就是永久的。</p><h1 id="并发事务问题" tabindex="-1"><a class="header-anchor" href="#并发事务问题"><span>并发事务问题</span></a></h1><ul><li><p>脏读 一个事务读到另外一个事务还没有提交的数据。 当前面的事务执行回滚操作，另外的事务查询到的信息就没有价值了</p></li><li><p>不可重复读 一个事务先后读取同一条记录，但两次读取的数据不同，称之为不可重复读。 当一条事务执行时先查询了数据库，然后另一个并发事务修改了数据库，这样这条事务再执行查询时就会和前面查询的结果不同</p></li><li><p>幻读 一个事务按照条件查询数据时，没有对应的数据行，但是在插入数据时，又发现这行数据已经存在，好像出现了“幻影”。 一条事务查询时发现一个主键不存在（主键独立且唯一）此时另一条事务插入了该主键，这条事务再插入相同主键时就会发生冲突</p></li></ul><h2 id="事务隔离级别" tabindex="-1"><a class="header-anchor" href="#事务隔离级别"><span>事务隔离级别</span></a></h2><table><thead><tr><th>隔离级别</th><th>脏读</th><th>不可重复读</th><th>幻读</th></tr></thead><tbody><tr><td>Read uncommitted读未提交</td><td>t</td><td>t</td><td>t</td></tr><tr><td>Read committed读已提交</td><td>f</td><td>t</td><td>t</td></tr><tr><td>Repeatable Read(默认)可重复读</td><td>f</td><td>f</td><td>t</td></tr><tr><td>Serializable串行化</td><td>f</td><td>f</td><td>f</td></tr><tr><td>这个默认隔离级别是MySQL的，其他的数据库可能不同</td><td></td><td></td><td></td></tr><tr><td>从上至下安全性依次提高，但性能依次降低，要选择合适的隔离级别</td><td></td><td></td><td></td></tr></tbody></table><p>查看事务隔离级别</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>SELECT@@TRANSACTION_ISOLATION;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>设置事务隔离级别</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>SET [SESSION| GLOBAL] TRANSACTION ISOLATION LEVEL {READ UNCOMMITTED | READ COMMITTED | REPEATABLE READ | SERIALIZABLE}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>session会话级别，表示只针对当前客户端窗口有效 global全部，针对所有客户端有效</p><p>在串行化级别时当一个事务开启时其他事务不能执行，只能等该事务执行完才能执行</p><h1 id="引擎" tabindex="-1"><a class="header-anchor" href="#引擎"><span>引擎</span></a></h1><h1 id="innodb" tabindex="-1"><a class="header-anchor" href="#innodb"><span>InnoDB</span></a></h1><p>在查询建表语句时会显示使用的引擎，如果不指定默认使用lnnoDB 使用<code>show engines</code>展示所有引|擎及其信息 <strong>InnoDB逻辑存储结构</strong> ![[Clip_2024-03-25_11-29-42.png]] 其中page和extent都是固定的大小</p><h1 id="myisam" tabindex="-1"><a class="header-anchor" href="#myisam"><span>MyISAM</span></a></h1><p>MyISAM是MySQL早期的默认存储引擎. 特点 不支持事务，不支持外键 支持表锁，不支持行锁 访问速度快 文件 XXX.sdi：存储表结构信息 XXX.MYD:存储数据 XXX.MYI:存储索引</p><h1 id="memory" tabindex="-1"><a class="header-anchor" href="#memory"><span>Memory</span></a></h1><p>Memory引擎的表数据时存储在内存中的，由于受到硬件问题、或断电问题的影响，只能将这些表作为临时表或缓存使用。 特点 内存存放 hash索引（默认） 文件 xxx.sdi：存储表结构信息</p><p>InnoDB：是Mysq|的默认存储引擎，支持事务、外键。如果应用对事务的完整性有比较高的要求，在并发条件下要求数据的一致性，数据操作除了插入和查询之外，还包含很多的更新、删除操作，那么InnoDB存储引擎是比较合适的选择。 MyISAM：如果应用是以读操作和插入操作为主，只有很少的更新和删除操作，并且对事务的完整性、并发性要求不是很高，那么选择这个存储引擎是非常合适的。 MEMORY：将所有数据保存在内存中，访问速度快，通常用于临时表及缓存。MEMORY的缺陷就是对表的大小有限制，太大的表无法缓存在内存中，而且无法保障数据的安全性。</p><table><thead><tr><th>特点</th><th>InnoDB</th><th>MyISAM</th><th>Memory</th></tr></thead><tbody><tr><td>存储限制</td><td>64TB</td><td>有</td><td>有</td></tr><tr><td>事务安全</td><td>支持</td><td></td><td></td></tr><tr><td>锁机制</td><td>行锁</td><td>表锁</td><td>表锁</td></tr><tr><td>B+tree索引</td><td>支持</td><td>支持</td><td>支持</td></tr><tr><td>Hash索引</td><td></td><td></td><td>支持</td></tr><tr><td>全文索引</td><td>支持（5.6版本后）</td><td>支持</td><td></td></tr><tr><td>空间使用</td><td>高</td><td>低</td><td>N/A</td></tr><tr><td>内存使用</td><td>高</td><td>低</td><td>中等</td></tr><tr><td>批量插入速度</td><td>低</td><td>高</td><td>高</td></tr><tr><td>支持外键</td><td>支持</td><td></td><td></td></tr></tbody></table>`,122)]))}const h=s(d,[["render",n]]),p=JSON.parse('{"path":"/tools/mysql/2/","title":"2 进阶","lang":"zh-CN","frontmatter":{"title":"2 进阶","createTime":"2025/06/22 11:06:16","permalink":"/tools/mysql/2/"},"readingTime":{"minutes":13.92,"words":4175},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/MySQL/2 进阶.md","headers":[]}');export{h as comp,p as data};
